#!/bin/bash

# =====================================================================
# Universal Vegeta Test Target Generator - Multi-blockchain Support
# Supports address files generated by fetch_active_accounts.py
# =====================================================================

# Load configuration file
if ! source "$(dirname "${BASH_SOURCE[0]}")/../config/config_loader.sh" 2>/dev/null; then
    echo "❌ Error: Configuration file loading failed" >&2
    exit 1
fi

# Intelligent configuration check and repair
if [[ -z "${CURRENT_RPC_METHODS_STRING:-}" ]]; then
    echo "⚠️ Warning: CURRENT_RPC_METHODS_STRING not set, attempting to recalculate..." >&2
    CURRENT_RPC_METHODS_STRING="$(get_current_rpc_methods)"
    if [[ -z "$CURRENT_RPC_METHODS_STRING" ]]; then
        echo "❌ Error: Unable to get RPC method configuration" >&2
        echo "💡 Hint: Please check if BLOCKCHAIN_NODE and RPC_MODE environment variables are set correctly" >&2
        exit 1
    fi
    echo "✅ Configuration recalculation completed: $CURRENT_RPC_METHODS_STRING" >&2
else
    echo "✅ Configuration exists: $CURRENT_RPC_METHODS_STRING" >&2
    # When configuration exists, perform simple consistency check
    if [[ -n "$CHAIN_CONFIG" && "$CHAIN_CONFIG" != "null" ]]; then
        expected_method=$(echo "$CHAIN_CONFIG" | jq -r ".rpc_methods.\"$(echo "${RPC_MODE:-single}" | tr '[:upper:]' '[:lower:]')\"" 2>/dev/null)
        if [[ -n "$expected_method" && "$expected_method" != "null" && "$CURRENT_RPC_METHODS_STRING" != "$expected_method" ]]; then
            echo "🔧 Configuration inconsistency, auto-repair: $expected_method" >&2
            CURRENT_RPC_METHODS_STRING="$expected_method"
        fi
    fi
fi

# Ensure RPC method array is initialized
if [[ -z "${CURRENT_RPC_METHODS_ARRAY:-}" ]]; then
    IFS=',' read -ra CURRENT_RPC_METHODS_ARRAY <<< "$CURRENT_RPC_METHODS_STRING"
fi

# Initialize variables (maintain backward compatibility)
VERBOSE=${VERBOSE:-false}

# Help information
show_help() {
    echo "Universal Vegeta Test Target Generator - Multi-blockchain Support"
    echo "Usage: $0 [options]"
    echo ""
    echo "Options:"
    echo "  -h, --help                 Show help information"
    echo "  -a, --accounts-file FILE   Input accounts file (default: ${ACCOUNTS_OUTPUT_FILE})"
    echo "  -o, --output FILE          Output target file (automatically selected based on mode)"
    echo "  --rpc-mode MODE            RPC mode: single, mixed (default: $RPC_MODE)"
    echo "  --rpc-url URL              RPC endpoint URL (default: $LOCAL_RPC_URL)"
    echo "  --output-single FILE       Single method target output file"
    echo "  --output-mixed FILE        Mixed method target output file"
    echo "  -v, --verbose              Enable verbose output"
    echo ""
    echo "Supported blockchains: solana, ethereum, bsc, base, polygon, scroll, starknet, sui"
    echo "Current blockchain: $BLOCKCHAIN_NODE"
    echo "RPC modes:"
    echo "  single: Generate targets using single RPC method"
    echo "  mixed: Generate targets using multiple RPC methods"
    echo ""
}

generate_rpc_json() {
    # Single-target wrapper for legacy callers / debugging.
    # Production path uses build_targets_batch() — see generate_targets().
    local method="$1"
    local address="$2"
    local rpc_url="$LOCAL_RPC_URL"
    local script_dir="$(dirname "${BASH_SOURCE[0]}")"
    python3 "${script_dir}/chain_adapters/cli.py" build-target \
        --chain "$BLOCKCHAIN_NODE" \
        --method "$method" \
        --address "$address" \
        --rpc-url "$rpc_url"
}

summarize_methods() {
    local methods=()
    local counts=()
    local method i found
    for method in "$@"; do
        found=false
        for ((i = 0; i < ${#methods[@]}; i++)); do
            if [[ "${methods[$i]}" == "$method" ]]; then
                counts[$i]=$((counts[$i] + 1))
                found=true
                break
            fi
        done
        if [[ "$found" == "false" ]]; then
            methods+=("$method")
            counts+=(1)
        fi
    done
    local summary=""
    for ((i = 0; i < ${#methods[@]}; i++)); do
        if [[ -n "$summary" ]]; then
            summary+=", "
        fi
        summary+="${methods[$i]}=${counts[$i]}"
    done
    echo "$summary"
}

# Parameter parsing
parse_args() {
    while [[ $# -gt 0 ]]; do
        case $1 in
            -h|--help)
                show_help
                exit 0
                ;;
            -a|--accounts-file)
                ACCOUNTS_OUTPUT_FILE="$2"
                shift 2
                ;;
            -o|--output)
                USER_OUTPUT_FILE="$2"
                shift 2
                ;;
            --rpc-mode)
                RPC_MODE="$2"
                echo "🔄 RPC mode changed to: $RPC_MODE" >&2
                # When user actively changes RPC mode, directly recalculate
                if [[ -n "$CHAIN_CONFIG" && "$CHAIN_CONFIG" != "null" ]]; then
                    local rpc_mode_lower
                    rpc_mode_lower=$(echo "$RPC_MODE" | tr '[:upper:]' '[:lower:]')
                    CURRENT_RPC_METHODS_STRING=$(echo "$CHAIN_CONFIG" | jq -r ".rpc_methods.\"$rpc_mode_lower\"" 2>/dev/null)
                else
                    echo "⚠️ Warning: CHAIN_CONFIG unavailable, using fallback method" >&2
                    CURRENT_RPC_METHODS_STRING=$(get_current_rpc_methods)
                fi
                IFS=',' read -ra CURRENT_RPC_METHODS_ARRAY <<< "$CURRENT_RPC_METHODS_STRING"
                echo "✅ RPC mode switch completed: $CURRENT_RPC_METHODS_STRING" >&2
                shift 2
                ;;
            --rpc-url)
                LOCAL_RPC_URL="$2"
                shift 2
                ;;
            --output-single)
                SINGLE_METHOD_TARGETS_FILE="$2"
                shift 2
                ;;
            --output-mixed)
                MIXED_METHOD_TARGETS_FILE="$2"
                shift 2
                ;;
            -v|--verbose)
                VERBOSE=true
                shift
                ;;
            *)
                echo "Unknown option: $1" >&2
                shift
                ;;
        esac
    done

    # Set current output file based on RPC mode
    if [[ "$RPC_MODE" == "single" ]]; then
        CURRENT_OUTPUT_FILE="$SINGLE_METHOD_TARGETS_FILE"
    elif [[ "$RPC_MODE" == "mixed" ]]; then
        CURRENT_OUTPUT_FILE="$MIXED_METHOD_TARGETS_FILE"
    else
        echo "❌ Error: Invalid RPC mode: $RPC_MODE" >&2
        show_help
        return 1
    fi

    # If user specified output file via -o, override default setting
    if [[ -n "${USER_OUTPUT_FILE:-}" ]]; then
        CURRENT_OUTPUT_FILE="$USER_OUTPUT_FILE"
    fi
}

# Check dependencies
check_dependencies() {
    if ! command -v jq &> /dev/null; then
        echo "❌ Error: jq not installed" >&2
        return 1
    fi
}

# Check required configuration variables
check_required_variables() {
    local required_vars=(
        "ACCOUNTS_OUTPUT_FILE"
        "SINGLE_METHOD_TARGETS_FILE"
        "MIXED_METHOD_TARGETS_FILE"
        "LOCAL_RPC_URL"
        "BLOCKCHAIN_NODE"
        "CURRENT_RPC_METHODS_STRING"
    )

    local missing_vars=()
    for var in "${required_vars[@]}"; do
        if [[ -z "${!var:-}" ]]; then
            missing_vars+=("$var")
        fi
    done

    if [[ ${#missing_vars[@]} -gt 0 ]]; then
        echo "❌ Error: Required variables not set:" >&2
        for var in "${missing_vars[@]}"; do
            echo "  - $var" >&2
        done
        echo "Please ensure config_loader.sh is loaded correctly" >&2
        return 1
    fi

    return 0
}

load_mixed_weighted_methods() {
    if [[ "${RPC_MODE:-single}" != "mixed" ]]; then
        return 0
    fi
    if [[ -z "${CHAIN_CONFIG:-}" || "$CHAIN_CONFIG" == "null" ]]; then
        return 0
    fi

    local weighted_rows
    weighted_rows=$(echo "$CHAIN_CONFIG" | jq -r '
        (.rpc_methods.mixed_weighted // [])[]?
        | select(.method != null)
        | [.method, (.weight // 1)]
        | @tsv
    ' 2>/dev/null)

    if [[ -z "$weighted_rows" ]]; then
        return 0
    fi

    local methods=()
    local weights=()
    local total_weight=0
    local method weight
    while IFS=$'\t' read -r method weight; do
        [[ -z "$method" ]] && continue
        if ! [[ "$weight" =~ ^[0-9]+$ ]]; then
            weight=1
        fi
        if (( weight < 1 )); then
            weight=1
        fi
        methods+=("$method")
        weights+=("$weight")
        total_weight=$((total_weight + weight))
    done <<< "$weighted_rows"

    if [[ ${#methods[@]} -eq 0 || "$total_weight" -le 0 ]]; then
        return 0
    fi

    # Build a smooth weighted sequence instead of grouped expansion.
    # Grouped [A A A ... B B B ...] is technically weighted, but short runs can
    # hammer only the first method. Smooth weighted round-robin keeps every
    # prefix closer to the configured ratio.
    local sequence=()
    local remaining=()
    local scores=()
    local idx pick best_score i
    for ((i = 0; i < ${#methods[@]}; i++)); do
        remaining+=("${weights[$i]}")
        scores+=(0)
    done

    for ((idx = 0; idx < total_weight; idx++)); do
        pick=-1
        best_score=-1
        for ((i = 0; i < ${#methods[@]}; i++)); do
            if (( remaining[$i] <= 0 )); then
                continue
            fi
            scores[$i]=$((scores[$i] + weights[$i]))
            if (( pick < 0 || scores[$i] > best_score )); then
                pick=$i
                best_score=${scores[$i]}
            fi
        done
        if (( pick < 0 )); then
            break
        fi
        sequence+=("${methods[$pick]}")
        remaining[$pick]=$((remaining[$pick] - 1))
        scores[$pick]=$((scores[$pick] - total_weight))
    done

    CURRENT_RPC_METHODS_ARRAY=("${sequence[@]}")
    local joined=""
    for method in "${sequence[@]}"; do
        if [[ -n "$joined" ]]; then
            joined+=","
        fi
        joined+="$method"
    done
    CURRENT_RPC_METHODS_STRING="$joined"
    MIXED_WEIGHT_TOTAL="$total_weight"
}

# Check input file
check_input_file() {
    if [[ ! -f "$ACCOUNTS_OUTPUT_FILE" ]]; then
        echo "❌ Error: Accounts file does not exist: $ACCOUNTS_OUTPUT_FILE" >&2
        return 1
    fi

    # Check if file is empty
    if [[ ! -s "$ACCOUNTS_OUTPUT_FILE" ]]; then
        echo "❌ Error: Accounts file is empty: $ACCOUNTS_OUTPUT_FILE" >&2
        return 1
    fi
}

# Generate test targets - using configured method list
generate_targets() {
    echo "🎯 Generating Vegeta test targets..." >&2
    echo "   Blockchain type: $BLOCKCHAIN_NODE" >&2
    echo "   RPC mode: $RPC_MODE" >&2
    echo "   RPC methods: $CURRENT_RPC_METHODS_STRING" >&2
    echo "   Input file: $ACCOUNTS_OUTPUT_FILE" >&2
    echo "   Output file: $CURRENT_OUTPUT_FILE" >&2

    # Create output directory
    mkdir -p "$(dirname "$CURRENT_OUTPUT_FILE")"

    # Clear output file
    > "$CURRENT_OUTPUT_FILE"

    # Read account list
    local accounts=()
    while IFS= read -r address; do
        [[ -z "$address" ]] && continue
        accounts+=("$address")
    done < "$ACCOUNTS_OUTPUT_FILE"

    if [[ ${#accounts[@]} -eq 0 ]]; then
        echo "❌ Error: Accounts file is empty or contains no valid addresses" >&2
        return 1
    fi

    echo "✅ Read ${#accounts[@]} accounts" >&2

    # Generate targets — batch path: emit TSV (method\taddress) to cli.py
    # build-targets-batch, which writes all vegeta targets in a single
    # python invocation. Avoids per-target subprocess fork (50ms × N).
    local script_dir="$(dirname "${BASH_SOURCE[0]}")"
    local batch_cli="${script_dir}/chain_adapters/cli.py"

    if [[ "$RPC_MODE" == "single" ]]; then
        # Single method mode
        local method="${CURRENT_RPC_METHODS_ARRAY[0]}"
        echo "📝 Using single method: $method" >&2

        # Stream TSV to cli batch
        for address in "${accounts[@]}"; do
            printf '%s\t%s\n' "$method" "$address"
        done | python3 "$batch_cli" build-targets-batch \
                 --chain "$BLOCKCHAIN_NODE" \
                 --rpc-url "$LOCAL_RPC_URL" \
                 > "$CURRENT_OUTPUT_FILE"
    else
        # Mixed method mode
        load_mixed_weighted_methods
        local method_count=${#CURRENT_RPC_METHODS_ARRAY[@]}
        if [[ "$method_count" -eq 0 ]]; then
            echo "❌ Error: No mixed RPC methods configured" >&2
            return 1
        fi

        echo "📝 Using mixed weighted methods: $(summarize_methods "${CURRENT_RPC_METHODS_ARRAY[@]}")" >&2
        echo "📝 Mixed weighted sequence length: $method_count" >&2

        local account_index=0
        for address in "${accounts[@]}"; do
            local method_index=$((account_index % method_count))
            local method="${CURRENT_RPC_METHODS_ARRAY[$method_index]}"
            printf '%s\t%s\n' "$method" "$address"
            account_index=$((account_index + 1))
        done | python3 "$batch_cli" build-targets-batch \
                 --chain "$BLOCKCHAIN_NODE" \
                 --rpc-url "$LOCAL_RPC_URL" \
                 > "$CURRENT_OUTPUT_FILE"
    fi

    # Final count from output file (subshell var doesn't propagate)
    local count
    count=$(wc -l < "$CURRENT_OUTPUT_FILE")

    echo "✅ Successfully generated $count test targets" >&2

    # Validate generated JSON
    if [[ "$VERBOSE" == "true" ]]; then
        echo "🔍 Validating first target:" >&2
        head -n 1 "$CURRENT_OUTPUT_FILE" | jq '.' 2>/dev/null || echo "   JSON format validation failed" >&2

        echo "🔍 Validating request body:" >&2
        head -n 1 "$CURRENT_OUTPUT_FILE" | jq -r '.body' 2>/dev/null | base64 -d 2>/dev/null | jq '.' 2>/dev/null || echo "   Request body decoding failed" >&2

        echo "📊 Total targets: $(wc -l < "$CURRENT_OUTPUT_FILE")" >&2
    fi
}

# Main function
main() {
    # Check dependencies
    if ! check_dependencies; then
        exit 1
    fi

    # Check required configuration variables
    if ! check_required_variables; then
        exit 1
    fi

    # Parse arguments
    parse_args "$@"

    # Final configuration validation and repair
    if [[ -z "${CURRENT_RPC_METHODS_STRING:-}" ]]; then
        echo "❌ Fatal error: RPC method configuration still empty after argument parsing" >&2
        echo "   BLOCKCHAIN_NODE: ${BLOCKCHAIN_NODE:-not set}" >&2
        echo "   RPC_MODE: ${RPC_MODE:-not set}" >&2

        if command -v get_current_rpc_methods >/dev/null 2>&1; then
            CURRENT_RPC_METHODS_STRING=$(get_current_rpc_methods)
            if [[ -n "$CURRENT_RPC_METHODS_STRING" ]]; then
                echo "✅ Final repair successful: $CURRENT_RPC_METHODS_STRING" >&2
            else
                exit 1
            fi
        else
            exit 1
        fi
    fi
    
    # Ensure array is initialized
    if [[ -z "${CURRENT_RPC_METHODS_ARRAY:-}" ]]; then
        IFS=',' read -ra CURRENT_RPC_METHODS_ARRAY <<< "$CURRENT_RPC_METHODS_STRING"
    fi

    # Check input file
    if ! check_input_file; then
        exit 1
    fi

    # Generate test targets
    if ! generate_targets; then
        exit 1
    fi
}

# Execute main function
if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
    main "$@"
fi
